<?php require_once __DIR__ . '/app/auth.php'; require_login(); csrf_check(); $pdo=db();
if($_SERVER['REQUEST_METHOD']==='POST'){
  $action=$_POST['action']??''; $id=(int)($_POST['id']??0);
  if($action==='save'){
    $code=trim($_POST['customer_code'] ?: next_customer_code($pdo));
    $data=[$code,trim($_POST['name']),trim($_POST['address']),trim($_POST['phone']),(int)$_POST['package_id'],trim($_POST['registered_at']),(int)$_POST['due_day'],isset($_POST['is_active'])?1:0,trim($_POST['notes'])];
    if($id){$data[]=$id;$pdo->prepare('UPDATE customers SET customer_code=?,name=?,address=?,phone=?,package_id=?,registered_at=?,due_day=?,is_active=?,notes=? WHERE id=?')->execute($data);}
    else {$pdo->prepare('INSERT INTO customers(customer_code,name,address,phone,package_id,registered_at,due_day,is_active,notes) VALUES(?,?,?,?,?,?,?,?,?)')->execute($data);} }
  if($action==='toggle' && $id){$pdo->prepare('UPDATE customers SET is_active=1-is_active WHERE id=?')->execute([$id]);}
  redirect('customers.php');
}
require_once __DIR__ . '/app/layout.php'; $month=current_month();
$packages=$pdo->query('SELECT * FROM packages WHERE is_active=1 ORDER BY price ASC')->fetchAll();
$edit=null; if(isset($_GET['edit'])){$st=$pdo->prepare('SELECT * FROM customers WHERE id=?');$st->execute([(int)$_GET['edit']]);$edit=$st->fetch();}
$q=trim($_GET['q']??''); $where=''; $args=[]; if($q!==''){$where='WHERE c.name LIKE ? OR c.customer_code LIKE ? OR c.phone LIKE ? OR c.address LIKE ?';$args=array_fill(0,4,"%$q%");}
$st=$pdo->prepare("SELECT c.*,p.name package_name,p.price,(SELECT COUNT(*) FROM payments pay WHERE pay.customer_id=c.id AND pay.invoice_month=?) is_paid FROM customers c LEFT JOIN packages p ON p.id=c.package_id $where ORDER BY c.name ASC"); $execArgs=array_merge([$month],$args); $st->execute($execArgs); $rows=$st->fetchAll(); render_header('Data Pelanggan'); ?>
<div class="grid-2"><div class="card"><div class="panel-title"><h2>Database Pelanggan</h2><form><input class="rounded-xl border px-3 py-2" name="q" value="<?=e($q)?>" placeholder="Cari nama / ID / telepon"><button class="btn soft">Cari</button></form></div><div class="table-wrap"><table><thead><tr><th>ID</th><th>Nama</th><th>Kontak</th><th>Paket</th><th>Harga</th><th>Tempo</th><th>Status</th><th>Tagihan</th><th>Aksi</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><b><?=e($r['customer_code'])?></b></td><td><?=e($r['name'])?><br><small class="text-slate-500"><?=e($r['address'])?></small></td><td><?=e($r['phone'])?></td><td><?=e($r['package_name']??'-')?></td><td><?=rupiah($r['price']??0)?></td><td>Tgl <?=e($r['due_day'])?></td><td><span class="pill <?=$r['is_active']?'green':'red'?>"><?=$r['is_active']?'ON':'OFF'?></span></td><td><span class="pill <?=$r['is_paid']?'green':'orange'?>"><?=$r['is_paid']?'Lunas':'Belum'?></span></td><td class="flex gap-2 flex-wrap"><a class="btn soft" href="customers.php?edit=<?=$r['id']?>">Edit</a><a class="btn primary" href="payments.php?customer_id=<?=$r['id']?>">Bayar</a><form method="post"><input type="hidden" name="csrf" value="<?=e(csrf_token())?>"><input type="hidden" name="action" value="toggle"><input type="hidden" name="id" value="<?=$r['id']?>"><button class="btn red" type="submit"><?=$r['is_active']?'OFF':'ON'?></button></form></td></tr><?php endforeach;if(!$rows):?><tr><td colspan="9">Belum ada pelanggan.</td></tr><?php endif;?></tbody></table></div></div><form class="card form-card" method="post"><input type="hidden" name="csrf" value="<?=e(csrf_token())?>"><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?=e($edit['id']??0)?>"><div class="panel-title"><h2><?=$edit?'Edit':'Tambah'?> Pelanggan</h2></div><div class="form-grid"><div class="field"><label>ID Pelanggan</label><input name="customer_code" value="<?=e($edit['customer_code']??next_customer_code($pdo))?>"></div><div class="field"><label>Nama</label><input name="name" required value="<?=e($edit['name']??'')?>"></div><div class="field"><label>Telepon</label><input name="phone" value="<?=e($edit['phone']??'')?>"></div><div class="field"><label>Paket</label><select name="package_id" required><?php foreach($packages as $p):?><option value="<?=$p['id']?>" <?=($edit && $edit['package_id']==$p['id'])?'selected':''?>><?=e($p['name'])?> - <?=rupiah($p['price'])?></option><?php endforeach;?></select></div><div class="field"><label>Tanggal Registrasi</label><input name="registered_at" type="date" required value="<?=e($edit['registered_at']??date('Y-m-d'))?>"></div><div class="field"><label>Tanggal Jatuh Tempo</label><input name="due_day" type="number" min="1" max="31" value="<?=e($edit['due_day']??20)?>"></div><div class="field"><label>Status</label><label class="flex gap-2 items-center mt-3"><input type="checkbox" name="is_active" <?=(!$edit||$edit['is_active'])?'checked':''?>> Pelanggan ON</label></div><div class="field"><label>Alamat</label><textarea name="address" rows="3"><?=e($edit['address']??'')?></textarea></div><div class="field" style="grid-column:1/-1"><label>Catatan</label><textarea name="notes" rows="2"><?=e($edit['notes']??'')?></textarea></div></div><button class="btn primary mt-5">Simpan Pelanggan</button></form></div><?php render_footer(); ?>
